# Base class
class Animal:
    def __init__(self, name, sound):
        self.name = name
        self.sound = sound

    def speak(self):
        return f'{self.name} says {self.sound}'

    def __str__(self):
        return f'Animal({self.name})'

# Inheritance
class Dog(Animal):
    def __init__(self, name):
        super().__init__(name, 'Woof')
        self.tricks = []

    def learn_trick(self, trick):
        self.tricks.append(trick)

    def show_tricks(self):
        return f'{self.name} knows: {self.tricks}'

class Cat(Animal):
    def __init__(self, name):
        super().__init__(name, 'Meow')

    def speak(self):  # Polymorphism - override
        return f'{self.name} purrs... {self.sound}'

# Usage
dog = Dog('Rex')
cat = Cat('Whiskers')

print(dog.speak())
print(cat.speak())

dog.learn_trick('sit')
dog.learn_trick('shake')
print(dog.show_tricks())

# Polymorphism in action
animals = [dog, cat, Dog('Buddy')]
for animal in animals:
    print(animal.speak())

